      id: 'user-member-1',
      email: 'member@example.com',
      passwordHash: 'hashed_password_member', // Placeholder
      role: 'member',
      organizationId: defaultOrgId,
    });
  }

  findUserById(id: UserId): User | undefined {
    return this.users.find(u => u.id === id);
  }

  findUserByEmail(email: string): User | undefined {
    return this.users.find(u => u.email === email);
  }

  addUser(user: User): User {
    this.users.push(user);
    return user;
  }

  addInviteToken(token: InviteToken): InviteToken {
    this.inviteTokens.push(token);
    return token;
  }

  findInviteTokenById(id: InviteTokenId): InviteToken | undefined {
    return this.inviteTokens.find(t => t.id === id);
  }

  updateInviteToken(id: InviteTokenId, updates: Partial<InviteToken>): InviteToken | undefined {
    const index = this.inviteTokens.findIndex(t => t.id === id);
    if (index !== -1) {
      this.inviteTokens[index] = { ...this.inviteTokens[index], ...updates };
      return this.inviteTokens[index];
    }
    return undefined;
  }
}

