import { InviteToken, InviteRequest, Session, UserId, OrganizationId } from '../types';
import { db } from '../db';

export class InviteService {
  private readonly INVITE_EXPIRATION_HOURS = 24; // Invite tokens expire in 24 hours

  public async createInvite(
    inviteRequest: InviteRequest,
    inviterSession: Session,
    baseUrl: string // Base URL for the invite link
  ): Promise<{ inviteToken: InviteToken; inviteLink: string }> {
    const { email, role } = inviteRequest;
    const { userId: createdBy, organizationId } = inviterSession;

    // Check if a user with this email already exists in the organization
    const existingUser = db.findUserByEmail(email);
    if (existingUser && existingUser.organizationId === organizationId) {
      throw new Error('User with this email already exists in the organization.');
    }

    const inviteTokenId = crypto.randomUUID();
    const expiresAt = new Date(Date.now() + this.INVITE_EXPIRATION_HOURS * 60 * 60 * 1000);

    const newInviteToken: InviteToken = {
      id: inviteTokenId,
      email,
      role,
      organizationId,
      expiresAt,
      createdAt: new Date(),
      createdBy,
      usedAt: null,
      usedBy: null,
    };

    db.addInviteToken(newInviteToken);

    const inviteLink = `${baseUrl}/accept-invite?token=${inviteTokenId}`;

    return { inviteToken: newInviteToken, inviteLink };
  }

  public async redeemInvite(tokenId: string, newUserId: UserId): Promise<User> {
    const invite = db.findInviteTokenById(tokenId);

    if (!invite) {
      throw new Error('Invite token not found.');
    }
    if (invite.usedAt) {
      throw new Error('Invite token has already been used.');
    }
    if (invite.expiresAt < new Date()) {
      throw new Error('Invite token has expired.');
    }

    // Mark the token as used
    db.updateInviteToken(tokenId, { usedAt: new Date(), usedBy: newUserId });

    // Create the new user in the organization
    const newUser: User = {
      id: newUserId,
      email: invite.email,
      passwordHash: 'placeholder_for_new_user_password', // This would be set during the actual registration process
      role: invite.role,
      organizationId: invite.organizationId,
    };

    db.addUser(newUser);
    return newUser;
  }
}

export const inviteService = new InviteService();
